const e=JSON.parse('{"key":"v-2e2a1e60","path":"/learningNote/TypeScriptNote/%E7%AC%AC%E4%B8%80%E5%A4%A9.html","title":"TypeScript第一天 开始入门","lang":"zh-CN","frontmatter":{"title":"TypeScript第一天 开始入门","icon":"typescript","date":"2022-09-10T00:00:00.000Z","category":["TypeScript","Web"]},"headers":[{"level":2,"title":"0、TypeScript简介","slug":"_0、typescript简介","link":"#_0、typescript简介","children":[]},{"level":2,"title":"1、TypeScript 开发环境搭建","slug":"_1、typescript-开发环境搭建","link":"#_1、typescript-开发环境搭建","children":[]},{"level":2,"title":"2、基本类型","slug":"_2、基本类型","link":"#_2、基本类型","children":[{"level":3,"title":"2.1、类型的用法举例","slug":"_2-1、类型的用法举例","link":"#_2-1、类型的用法举例","children":[]},{"level":3,"title":"2.2、 类型断言","slug":"_2-2、-类型断言","link":"#_2-2、-类型断言","children":[]}]}],"git":{"createdTime":1692892792000,"updatedTime":1693300529000,"contributors":[{"name":"Jeacson_Snake","email":"Jeacson_Snake@outlook.com","commits":3}]},"readingTime":{"minutes":4.65,"words":1394},"filePathRelative":"learningNote/TypeScriptNote/第一天.md","localizedDate":"2022年9月10日","excerpt":"<h2> 0、TypeScript简介</h2>\\n<ol>\\n<li>TypeScript是JavaScript的超集。</li>\\n<li>它对JS进行了扩展，向JS中引入了类型的概念，并添加了许多新的特性。</li>\\n<li>TS代码需要通过编译器编译为JS，然后再交由JS解析器执行。</li>\\n<li>TS完全兼容JS，换言之，任何的JS代码都可以直接当成JS使用。</li>\\n<li>相较于JS而言，TS拥有了静态类型，更加严格的语法，更强大的功能；TS可以在代码执行前就完成代码的检查，减小了运行时异常的出现的几率；TS代码可以编译为任意版本的JS代码，可有效解决不同JS运行环境的兼容问题；同样的功能，TS的代码量要大于JS，但由于TS的代码结构更加清晰，变量类型更加明确，在后期代码的维护中TS却远远胜于JS。</li>\\n</ol>"}');export{e as data};
